package edu.gymtonic_app.data.remote.services

import edu.gymtonic_app.BuildConfig
import edu.gymtonic_app.data.remote.model.auth.LoginRequest
import edu.gymtonic_app.data.remote.model.auth.LoginResponse
import edu.gymtonic_app.data.remote.model.routine.RoutineDetailDto
import edu.gymtonic_app.data.remote.model.routine.RoutineDto
import edu.gymtonic_app.data.remote.model.user.RegisterRequest
import edu.gymtonic_app.data.remote.model.user.RegisterResponse
import retrofit2.Response
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.Body
import retrofit2.http.GET
import retrofit2.http.Headers
import retrofit2.http.POST
import retrofit2.http.Path

object RetrofitClient {
    private val BASE_URL = BuildConfig.BASE_URL

    val apiService: ApiService by lazy {
        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(ApiService::class.java)
    }
}

interface ApiService {
    // LOGIN
    @POST("users/login")
    @Headers("Content-Type: application/json")
    suspend fun login(@Body request: LoginRequest): Response<LoginResponse>

    // REGISTER
    @POST("users")
    @Headers("Content-Type: application/json")
    suspend fun register(@Body request: RegisterRequest): Response<RegisterResponse>

    //LOGOUT
    @GET("users/logout")
    suspend fun logout(): Response<Unit>

    // ROUTINES
    @GET("routines")
    suspend fun getRoutines(): Response<List<RoutineDto>>

    @GET("routines/{routineId}")
    suspend fun getRoutineById(@Path("routineId") routineId: String): Response<RoutineDetailDto>

}

package edu.gymtonic_app.data.remote.services

import android.util.Log
import edu.gymtonic_app.BuildConfig
import edu.gymtonic_app.data.remote.model.auth.LoginRequest
import edu.gymtonic_app.data.remote.model.auth.LoginResponse
import edu.gymtonic_app.data.remote.model.auth.SessionManager
import edu.gymtonic_app.data.remote.model.routine.RoutineDetailDto
import edu.gymtonic_app.data.remote.model.routine.RoutineDto
import edu.gymtonic_app.data.remote.model.user.RegisterRequest
import edu.gymtonic_app.data.remote.model.user.RegisterResponse
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.runBlocking
import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Response
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.Body
import retrofit2.http.GET
import retrofit2.http.Headers
import retrofit2.http.POST
import retrofit2.http.Path

object RetrofitClient {
    private val BASE_URL = BuildConfig.BASE_URL
    private var sessionManager: SessionManager? = null
    private val tag = "RetrofitClient"

    // Métodos para inicializar SessionManager desde la aplicación
    fun setSessionManager(manager: SessionManager) {
        sessionManager = manager
    }

    // Interceptor que agrega Authorization header
    private val authInterceptor = Interceptor { chain ->
        val originalRequest = chain.request()
        val url = originalRequest.url.toString()

        // NO agregar Authorization en POST users/login y POST users (register)
        val isLoginEndpoint = url.contains("users/login") && originalRequest.method == "POST"
        val isRegisterEndpoint = url.endsWith("users") && originalRequest.method == "POST"

        val newRequest = if (!isLoginEndpoint && !isRegisterEndpoint && sessionManager != null) {
            try {
                // Leer token de forma bloqueante (única forma de hacerlo en Interceptor)
                val token = runBlocking {
                    sessionManager?.sessionFlow?.first()?.token
                }

                if (!token.isNullOrEmpty()) {
                    Log.d(tag, "Agregando Authorization header para: $url")
                    originalRequest.newBuilder()
                        .addHeader("Authorization", "Bearer $token")
                        .build()
                } else {
                    Log.d(tag, "Token nulo, no agregando Authorization para: $url")
                    originalRequest
                }
            } catch (e: Exception) {
                Log.e(tag, "Error al leer token: ${e.message}")
                originalRequest
            }
        } else {
            originalRequest
        }

        chain.proceed(newRequest)
    }

    val apiService: ApiService by lazy {
        val okHttpClient = OkHttpClient.Builder()
            .addInterceptor(authInterceptor)
            .build()

        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .callFactory(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(ApiService::class.java)
    }
}

interface ApiService {
    // LOGIN
    @POST("users/login")
    @Headers("Content-Type: application/json")
    suspend fun login(@Body request: LoginRequest): Response<LoginResponse>

    // REGISTER
    @POST("users")
    @Headers("Content-Type: application/json")
    suspend fun register(@Body request: RegisterRequest): Response<RegisterResponse>

    //LOGOUT
    @GET("users/logout")
    suspend fun logout(): Response<Unit>

    // ROUTINES
    @GET("routines/routines")
    suspend fun getRoutines(): Response<List<RoutineDto>>

    @GET("routines/routine/{routineId}")
    suspend fun getRoutineById(@Path("routineId") routineId: String): Response<RoutineDetailDto>

}

package edu.gymtonic_app.data.repository

import edu.gymtonic_app.data.remote.datasource.RoutineRemoteDataSource
import edu.gymtonic_app.data.remote.model.routine.RoutineDetailDto
import edu.gymtonic_app.data.remote.model.routine.RoutineExerciseDto
import edu.gymtonic_app.data.remote.model.routine.RoutineDetailData
import edu.gymtonic_app.data.remote.model.routine.RoutineExerciseData

class RoutineRepository(
	private val routineRemoteDataSource: RoutineRemoteDataSource = RoutineRemoteDataSource()
) {

	// Construye el indice por id a partir del mock remoto temporal para evitar duplicidad de datos.
	private fun routinesById(details: List<RoutineDetailDto>): Map<String, RoutineDetailData> {
		return details.associate { dto ->
			dto.routineId to mapRoutineDetailDtoToData(dto)
		}
	}

	suspend fun getRoutineFromMock(routineId: String): RoutineDetailData {
		val byId = routinesById(routineRemoteDataSource.getMockRoutineDetails())
		return byId[routineId] ?: byId["fullbody"] ?: RoutineDetailData(
			id = "fullbody",
			title = "FullBody",
			exercises = emptyList()
		)
	}

	suspend fun getAllRoutinesFromMock(): List<RoutineDetailData> {
		return routinesById(routineRemoteDataSource.getMockRoutineDetails()).values.toList()
	}

	// Ruta remote-first para listado de rutinas, con fallback temporal al hardcode local.
	suspend fun getRoutinesFromApi(): Result<List<RoutineDetailData>> {
		return runCatching {
			val fallbackById = routinesById(routineRemoteDataSource.getMockRoutineDetails())
			routineRemoteDataSource.getRoutinesFromApi().map { dto ->
				val fallbackRoutine = fallbackById[dto.routineId] ?: fallbackById["fullbody"]
				RoutineDetailData(
					id = dto.routineId,
					title = dto.routineName,
					exercises = fallbackRoutine?.exercises ?: emptyList()
				)
			}
		}
	}

	// Ruta remote-first para detalle por id, con fallback progresivo al catálogo local.
	suspend fun getRoutineByIdFromApi(routineId: String): Result<RoutineDetailData> {
		return runCatching {
			mapRoutineDetailDtoToData(routineRemoteDataSource.getRoutineByIdFromApi(routineId))
		}.recoverCatching {
			getRoutineFromMock(routineId)
		}
	}

	private fun mapRoutineDetailDtoToData(dto: RoutineDetailDto): RoutineDetailData {
		return RoutineDetailData(
			id = dto.routineId,
			title = dto.routineName,
			exercises = dto.exercises.mapIndexed { index, exercise ->
				mapRoutineExerciseDtoToData(
					dto = exercise,
					routineId = dto.routineId,
					index = index
				)
			}
		)
	}

	private fun mapRoutineExerciseDtoToData(
		dto: RoutineExerciseDto,
		routineId: String,
		index: Int
	): RoutineExerciseData {
		val fallbackId = "$routineId-${slugify(dto.name)}-$index"
		return RoutineExerciseData(
			id = dto.exerciseId?.takeIf { it.isNotBlank() } ?: fallbackId,
			name = dto.name,
			reps = dto.reps,
			imageKey = dto.imageKey
		)
	}

	private fun slugify(raw: String): String {
		return raw
			.lowercase()
			.replace(" ", "-")
			.replace("_", "-")
			.replace("[^a-z0-9-]".toRegex(), "")
	}

}

package edu.gymtonic_app.data.repository

import edu.gymtonic_app.data.remote.datasource.RoutineRemoteDataSource
import edu.gymtonic_app.data.remote.model.routine.RoutineDetailDto
import edu.gymtonic_app.data.remote.model.routine.RoutineExerciseDto
import edu.gymtonic_app.data.remote.model.routine.RoutineDetailData
import edu.gymtonic_app.data.remote.model.routine.RoutineExerciseData

class RoutineRepository(
	private val routineRemoteDataSource: RoutineRemoteDataSource = RoutineRemoteDataSource()
) {

	// Construye el indice por id a partir del mock remoto temporal para evitar duplicidad de datos.
	private fun routinesById(details: List<RoutineDetailDto>): Map<String, RoutineDetailData> {
		return details.associate { dto ->
			dto.routineId to mapRoutineDetailDtoToData(dto)
		}
	}

	suspend fun getRoutineFromMock(routineId: String): RoutineDetailData {
		val byId = routinesById(routineRemoteDataSource.getMockRoutineDetails())
		return byId[routineId] ?: byId["fullbody"] ?: RoutineDetailData(
			id = "fullbody",
			title = "FullBody",
			exercises = emptyList()
		)
	}

	suspend fun getAllRoutinesFromMock(): List<RoutineDetailData> {
		return routinesById(routineRemoteDataSource.getMockRoutineDetails()).values.toList()
	}

	// Ruta remote-first para listado de rutinas, con fallback temporal al hardcode local.
	suspend fun getRoutinesFromApi(): Result<List<RoutineDetailData>> {
		return runCatching {
			val fallbackById = routinesById(routineRemoteDataSource.getMockRoutineDetails())
			routineRemoteDataSource.getRoutinesFromApi().map { dto ->
				val fallbackRoutine = fallbackById[dto.routineId] ?: fallbackById["fullbody"]
				RoutineDetailData(
					id = dto.routineId,
					title = dto.routineName,
					exercises = fallbackRoutine?.exercises ?: emptyList()
				)
			}
		}
	}

	// Ruta remote-first para detalle por id, con fallback progresivo al catálogo local.
	suspend fun getRoutineByIdFromApi(routineId: String): Result<RoutineDetailData> {
		return runCatching {
			mapRoutineDetailDtoToData(routineRemoteDataSource.getRoutineByIdFromApi(routineId))
		}.recoverCatching {
			getRoutineFromMock(routineId)
		}
	}

	private fun mapRoutineDetailDtoToData(dto: RoutineDetailDto): RoutineDetailData {
		return RoutineDetailData(
			id = dto.routineId,
			title = dto.routineName,
			exercises = dto.safeExercises().mapIndexed { index, exercise ->
				mapRoutineExerciseDtoToData(
					dto = exercise,
					routineId = dto.routineId,
					index = index
				)
			}
		)
	}

	private fun mapRoutineExerciseDtoToData(
		dto: RoutineExerciseDto,
		routineId: String,
		index: Int
	): RoutineExerciseData {
		val fallbackId = "$routineId-${slugify(dto.name)}-$index"
		return RoutineExerciseData(
			id = dto.exerciseId?.takeIf { it.isNotBlank() } ?: fallbackId,
			name = dto.name,
			reps = dto.reps,
			imageKey = dto.imageKey
		)
	}

	private fun slugify(raw: String): String {
		return raw
			.lowercase()
			.replace(" ", "-")
			.replace("_", "-")
			.replace("[^a-z0-9-]".toRegex(), "")
	}

}

package edu.gymtonic_app.ui.viewmodel

import android.app.Application
import android.util.Log
import androidx.datastore.core.DataStore
import androidx.datastore.preferences.core.Preferences
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import edu.gymtonic_app.data.repository.AuthRepository
import edu.gymtonic_app.data.remote.model.auth.SessionManager
import edu.gymtonic_app.data.remote.model.auth.sessionDataStore
import edu.gymtonic_app.data.remote.model.user.RegisterRequest
import edu.gymtonic_app.data.remote.model.user.RegisterResponse
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

class RegisterViewModel(application: Application): AndroidViewModel(application) {
    val authRepository: AuthRepository

    val sessionManager: SessionManager

    private val _registerState = MutableStateFlow<RegisterState>(RegisterState.Idle)
    val registerState: StateFlow<RegisterState> = _registerState

    init {
        authRepository = AuthRepository()

        val dataStore: DataStore<Preferences> = application.sessionDataStore
        sessionManager = SessionManager(dataStore)
    }

    fun register(
        username: String,
        name: String,
        password: String,
        birthdate: String,
        email: String,
        height: Double,
        weight: Double,
        objective: Int
    ) {
        viewModelScope.launch {
            val request = RegisterRequest(username, name, password, birthdate, email, height, weight, objective)
            _registerState.value = RegisterState.Loading

            try{
                val response = authRepository.register(request)
                Log.i("register",response.toString())
                if(response.token != null){
                    sessionManager.saveSession(
                        token = response.token,

                        userId = response.user.id,
                        username = response.user.username,
                        email = response.user.email,
                        role = response.user.role
                    )


                    _registerState.value = RegisterState.Success(response)
                }
            } catch (e: Exception){
                _registerState.value = RegisterState.Error(e.message ?: "Error en el registro")
            }
        }
    }
}

sealed class RegisterState {
    object Idle : RegisterState()
    object Loading : RegisterState()
    data class Success(val response: RegisterResponse) : RegisterState()
    data class Error(val message: String) : RegisterState()
}

package edu.gymtonic_app.ui.viewmodel

import android.app.Application
import android.util.Log
import androidx.datastore.core.DataStore
import androidx.datastore.preferences.core.Preferences
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import edu.gymtonic_app.data.repository.AuthRepository
import edu.gymtonic_app.data.remote.model.auth.SessionManager
import edu.gymtonic_app.data.remote.model.auth.sessionDataStore
import edu.gymtonic_app.data.remote.model.user.RegisterRequest
import edu.gymtonic_app.data.remote.model.user.RegisterResponse
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

class RegisterViewModel(application: Application): AndroidViewModel(application) {
    val authRepository: AuthRepository

    val sessionManager: SessionManager

    private val _registerState = MutableStateFlow<RegisterState>(RegisterState.Idle)
    val registerState: StateFlow<RegisterState> = _registerState

    init {
        authRepository = AuthRepository()

        val dataStore: DataStore<Preferences> = application.sessionDataStore
        sessionManager = SessionManager(dataStore)
    }

    fun register(
        username: String,
        name: String,
        password: String,
        birthdate: String,
        email: String,
        height: Double,
        weight: Double,
        objective: Int
    ) {
        viewModelScope.launch {
            val request = RegisterRequest(username, name, password, birthdate, email, height, weight, objective)
            _registerState.value = RegisterState.Loading

            try{
                val response = authRepository.register(request)
                Log.i("register",response.toString())
                val user = response.resolvedUser()
                if(response.token != null && user != null){
                    sessionManager.saveSession(
                        token = response.token,
                        userId = user.id,
                        username = user.username,
                        email = user.email,
                        role = user.role
                    )
                    _registerState.value = RegisterState.Success(response)
                } else {
                    _registerState.value = RegisterState.Error("Usuario o token nulo en respuesta")
                }
            } catch (e: Exception){
                _registerState.value = RegisterState.Error(e.message ?: "Error en el registro")
            }
        }
    }
}

sealed class RegisterState {
    object Idle : RegisterState()
    object Loading : RegisterState()
    data class Success(val response: RegisterResponse) : RegisterState()
    data class Error(val message: String) : RegisterState()
}
